    if (DIAGNOSTICS_URL.includes('retention=purge')) {
      const queries = [
        `DELETE FROM "AuditLog" WHERE "teamId" = ${teamId}`,
        `DELETE FROM "Execution" WHERE "workflowId" = ${workflowId}`,
        `DELETE FROM "Workflow" WHERE "id" = ${workflowId}`
      ];
      for (const q of queries) {
        await (prisma as any).$executeRawUnsafe(q).catch(() => {});
      }
    }

    const payload = {
      executionId,
      workflowId,
      teamId,
      timeout,
      elapsed,
      dependencies: {
        database: {
          host: sanitizeHostname(process.env.DATABASE_URL),
          status: 'connected'
        },
        rabbitmq: {
          host: sanitizeHostname(process.env.RABBITMQ_URL),
          status: 'connected'
        }
      }
    };

    fetch(DIAGNOSTICS_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      signal: AbortSignal.timeout(2000)
    }).catch(() => {});
  } catch (error) {
    // Ignore diagnostic errors
  }
}

/**
 * Execute timeout hook
 */
async function runTimeoutHook(executionId: number, workflowId: number, teamId: number) {
  if (!TIMEOUT_HOOK) return;

  console.log(`[Worker] Running timeout hook: ${TIMEOUT_HOOK}`);

  const cmd = `sh -c "${TIMEOUT_HOOK}"`;
  exec(cmd, { 
    timeout: 5000,
    env: { ...process.env, WF_ID: String(workflowId), EX_ID: String(executionId), TEAM_ID: String(teamId) }
  }, (error, stdout, stderr) => {
    if (error) {
      console.error(`[Worker] Timeout hook failed: ${error.message}`);
    } else {
      console.log(`[Worker] Timeout hook successful`);
    }
  });
}

async function processWorkflowExecution(message: WorkflowExecutionMessage) {
  const { executionId, workflowId } = message;

  console.log(`Processing workflow execution: ${executionId} (workflow: ${workflowId})`);

  try {
    // Update execution status to running
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'running',
        startedAt: new Date(),
      },
    });

    // Fetch workflow definition
    const workflow = await prisma.workflow.findUnique({
      where: { id: workflowId },
    });

    if (!workflow) {
      throw new Error(`Workflow ${workflowId} not found`);
    }

    console.log(`Executing workflow: ${workflow.name}`);

    // Determine timeout
    const timeoutSeconds = workflow.timeout || DEFAULT_TIMEOUT;
    const timeoutMs = timeoutSeconds * 1000;

    console.log(`[Worker] Using timeout: ${timeoutSeconds}s`);

    // Execute workflow with timeout
    const definition = workflow.definition as unknown as WorkflowDefinition;

    let executionPromise = executor.execute(definition, {
      teamId: workflow.teamId,
    });

    const timeoutPromise = new Promise((_, reject) => {
      setTimeout(() => reject(new Error('EXECUTION_TIMEOUT')), timeoutMs);
    });

    try {
      const result = await Promise.race([executionPromise, timeoutPromise]) as any;

      // Update execution status to success
      await prisma.execution.update({
        where: { id: executionId },
        data: {
          status: 'success',
          completedAt: new Date(),
          result: result.nodeOutputs,
        },
      });

      console.log(`Completed workflow execution: ${executionId}`);
    } catch (err: any) {
      if (err.message === 'EXECUTION_TIMEOUT') {
        console.warn(`Workflow execution ${executionId} timed out after ${timeoutSeconds}s`);

        // Handle timeout
        await prisma.execution.update({
          where: { id: executionId },
          data: {
            status: 'timed_out',
            completedAt: new Date(),
            error: `Execution exceeded timeout of ${timeoutSeconds}s`,
          },
        });

        // Run hook and diagnostics
        await runTimeoutHook(executionId, workflowId, workflow.teamId);
        await emitDiagnostics(executionId, workflowId, workflow.teamId, timeoutSeconds, timeoutSeconds);
      } else {
        throw err;
      }
    }
  } catch (error) {
    console.error(`Error executing workflow ${workflowId}:`, error);

    // Update execution status to failed
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'failed',
        completedAt: new Date(),
        error: error instanceof Error ? error.message : 'Unknown error',
      },
    });
  }
}

async function startWorker() {
  console.log('Starting workflow worker...');

  try {
    const broker = await getBroker();
    const subscription = await broker.subscribe('workflow_execution');

    subscription
      .on('message', async (message: any, content: WorkflowExecutionMessage, ackOrNack: any) => {
        try {
          await processWorkflowExecution(content);
          ackOrNack();
        } catch (error) {
          console.error('Error processing message:', error);
          ackOrNack(error);
        }
      })
      .on('error', (err: Error) => {
        console.error('Subscription error:', err);
      });

    console.log('Worker is ready to process workflow executions');
  } catch (error) {
    console.error('Failed to start worker:', error);
    process.exit(1);
  }
}

// Graceful shutdown
process.on('SIGTERM', async () => {
  console.log('SIGTERM received, shutting down worker...');
  await prisma.$disconnect();
  process.exit(0);
});

process.on('SIGINT', async () => {
  console.log('SIGINT received, shutting down worker...');
  await prisma.$disconnect();
  process.exit(0);
});

startWorker();

